    "# function that validates the answers for the multiple choice question in the google form\n",
    "def check_multiple_choice(option):\n",
    "    valid = True\n",
    "    if option == \"Laptop\":\n",
    "        valid = True\n",
    "    elif option == \"Ipad\":\n",
    "        valid = True\n",
    "    elif option == \"Iphone\":\n",
    "        valid = True\n",
    "    elif option == \"Other\":\n",
    "        valid = True\n",
    "    else:\n",
    "        valid = False\n",
    "        \n",
    "    return valid\n",
