    "                if check_linear_scale(row[\"How did you perform during distance learning?\"]) == True:\n",
    "                    ratings.append(row[\"How did you perform during distance learning?\"])\n",
    "                    #This code adds up how many time each of my multiple choice options were selected\n",
    "                    if check_multiple_choice(row[\"What device did you use for online school?\"]) == True:\n",
    "                        laptop += row[\"What device did you use for online school?\"].count(\"Laptop\")\n",
    "                        ipad += row[\"What device did you use for online school?\"].count(\"Ipad\")\n",
    "                        iphone += row[\"What device did you use for online school?\"].count(\"Iphone\")\n",
    "                        other += row[\"What device did you use for online school?\"].count(\"Other\")\n",
    "                    else:\n",
    "                        print('\\n')\n",
