    "                        print('\\n')\n",
    "                else:\n",
    "                    print(check_linear_scale(row[\"How did you perform during distance learning?\"]))\n",
    "                    print('\\n')\n",
    "                    print(\"Error in line\",reader.line_num, \"is out of range or not a number.\")\n",
