    "#This function computes the mean of the ratings\n",
    "# arguments: a list variable\n",
    "# returns: mean statistic\n",
    "# outputs: the mean of some number\n",
    "\n",
    "def compute(some_list):\n",
    "    some_list = [int(x) for x in some_list]\n",
    "    mean = np.mean(some_list)\n",
    "    return mean\n",
