    "#This function opens and loads the big dataset\n",
    "# arguments: filename\n",
    "# returns: some dataframe\n",
    "\n",
    "def read_as_dataframe(filename):\n",
    "    df = pd.read_csv(filename)\n",
    "    return df\n",
