    "#This function computes the mean of the ratings\n",
    "# arguments: df\n",
    "# returns: df\n",
    "# outputs: cleans and processes the big dataset\n",
    "\n",
    "def clean_dataframe(df):\n",
    "    \n",
    "    print(\"Erros in this dataset include...\")\n",
    "    print(\"Duplicate rows need to get dropped.\")\n",
    "    print(\"Missing data cells need to get dropped.\")\n",
    "    print(\"Columns must get changed to the correct data type.\")\n",
    "    print(\"Index must be reset\")\n",
    "    print(\"Please wait one moment while the dataset gets cleaned\")\n",
    "    print('\\n')\n",
    "    df.dropna(inplace = True)\n",
    "    df.drop_duplicates(inplace = True)\n",
    "    df = df.reset_index(drop = True)\n",
    "    #if there are any duplicates, drop them and reset index\n",
    "    df.drop_duplicates(inplace = True)\n",
    "    df.value_counts(dropna = False)\n",
    "    df.reset_index(drop = True, inplace = True)\n",
    "\n",
    "    # convert values to correct data types\n",
    "    df['Time spent on self study'] = pd.to_numeric(df['Time spent on self study'])\n",
    "    df['Time spent on TV'] = pd.to_numeric(df['Time spent on TV'], errors='coerce')\n",
    "    df['ID'] = pd.to_numeric(df['ID'], errors='coerce')\n",
    "    df['Time utilized'] = df['Time utilized'].replace({'YES': True, 'NO': False})\n",
    "    df['Health issue during lockdown'] = df['Health issue during lockdown'].replace({'YES': True, 'NO': False})\n",
    "    df['Do you find yourself more connected with your family, close friends , relatives  ?'] = df['Do you find yourself more connected with your family, close friends , relatives  ?'].replace({'YES': True, 'NO': False})\n",
    "    df.reset_index(drop = True, inplace = True)\n",
    "\n",
    "    # drop columns that will not help with data-driven question.\n",
    "    df.drop(['Prefered social media platform'], axis = 1)\n",
    "    df.drop(['Do you find yourself more connected with your family, close friends , relatives  ?'], axis=1)\n",
    "    df.reset_index(drop = True, inplace = True)\n",
    "    print('\\n')\n",
    "    print(\"chapman_covid.csv has been cleaned and processed.\")\n",
    "    print('\\n')\n",
    "\n",
    "    return df\n",
    "\n",
    "\n",
    "# subset for all students under 22\n",
    "# arguments: df\n",
    "# returns: new variable for age grouping\n",
    "# outputs: use in stats and visuals\n",
    "\n",
    "def get_subset(df):\n",
    "    new_age = df[df[\"Age of Subject\"] <= 22]\n",
    "    df = df.reset_index(drop = True)\n",
    "    return new_age\n",
