    "#will display the average time spent in online school per age group\n",
    "# arguments: df\n",
    "# returns: a variable for the sum table\n",
    "# outputs: summary for average time age groups spent in class\n",
    "\n",
    "def groupby_sum_table(df):\n",
    "    \n",
    "    #sum_table = df.groupby\n",
    "    sum_table = df.groupby(\"Age of Subject\", as_index = True)['Time spent on Online Class'].mean()\n",
    "    df = df.reset_index(drop = True)\n",
    "    print('Average time Spent in Online Class For Each Age Group (hours)')\n",
    "    return sum_table\n",
    "\n",
    "\n",
    "\n",
    "#will display average time students spent doing anything school related\n",
    "# arguments: df\n",
    "# returns: a variable that contains a pivot table\n",
    "# outputs: pivot table for the average time students spent in class or self study\n",
    "\n",
    "def piv_sum_table(df):\n",
    "    piv_table = df.groupby(['Time spent on Online Class'])['Time spent on self study'].mean()\n",
    "    df = df.reset_index(drop = True)\n",
    "    print('Average time Spent in Online Class or On Self Study Per day (hours)')\n",
    "    return piv_table\n",
    "\n",
    "#creates bar visual\n",
    "def barVisual(df):\n",
    "    x = df['Age of Subject']\n",
    "    y = df['Time spent on Online Class']\n",
    "    plt.bar(x,y)\n",
    "    plt.title(\"Average Time spent in Online Class (hours) Per Age Group\")\n",
    "    plt.xlabel(\"Age of Subjects\")\n",
    "    plt.ylabel(\"Time spent on Online Class\")\n",
    "    plt.show()\n",
    "    print('Ages 19-20 Spent the most time in Online Class, both equal with 10 hours')\n",
    "    print('\\n')\n",
    "\n",
    " #creates line visual    \n",
    "def lineVisual(df):\n",
    "    public_online = 77\n",
    "    private_online = 73\n",
    "    overall_percent = 26/100\n",
    "    catch_up_summer_school = 10/100\n",
    "    school_summer_camp = 8/100\n",
    "    poor_grade_summer_school = 7/100\n",
    "    distance_tutors = 7/100\n",
    "    public_avg = public_online + overall_percent + catch_up_summer_school + school_summer_camp + poor_grade_summer_school + distance_tutors\n",
    "    private_avg = private_online + overall_percent + catch_up_summer_school + school_summer_camp + poor_grade_summer_school + distance_tutors\n",
    "\n",
    "    y = [public_online, private_online]\n",
    "    x = [public_avg, private_avg]\n",
    "    plt.plot(x,y)\n",
    "    plt.title(\"Public v Private % of Students who Needed Extra Help in Online School\")\n",
    "    plt.xlabel(\"Private - Public (%)\")\n",
    "    plt.ylabel(\"Public and Private\")\n",
    "    plt.show()\n",
    "\n",
    "# creates scatter plot\n",
    "def scatterplotVisual(df):\n",
    "    x = df[\"Age of Subject\"]\n",
    "    y = df[\"Rating of Online Class experience\"]\n",
    "    plt.scatter(x, y)\n",
    "    plt.title(\"Rating of Distance Learning from Ages 6 - 22\")\n",
    "    plt.xlabel(\"Age of Subjects\")\n",
    "    plt.ylabel(\"Rating of Online Class experience\")\n",
    "    plt.show()\n",
    "\n",
    "\n",
    "\n",
    "#creates pie chart\n",
    "def piechartVisual(df):\n",
    "    bins = [5, 10, 15, 20, 25]\n",
    "    labels = ['6-10', '11-15', '16-20', '21-25',]\n",
    "    \n",
    "    # Create a new column for the categorized ratings\n",
    "    df['Age'] = pd.cut(df['Age of Subject'], bins=bins, labels=labels, right=False)\n",
    "    \n",
    "    # Count the occurrences of each category\n",
    "    rating_counts = df['Age'].value_counts()\n",
    "\n",
    "    # Create the pie chart\n",
    "    plt.figure(figsize=(3, 3))\n",
    "    plt.pie(rating_counts, labels=rating_counts.index, autopct='%1.1f%%', startangle=140)\n",
    "    plt.title(\"Number of Students in Each Age Group\")\n",
    "    plt.axis('equal')\n",
    "    plt.show()\n",
    "    print('\\n')\n",
    "    print('This Chart shows the distribution of ratings for the online class experience among subjects aged 6-22.')\n",
    "    print('According to this Chart, Between ages 0-25, 21-25 years old were the majority of this survey with 52.6%')\n",
    "\n",
