    "#average value function which will return the average value in a given list\n",
    "def average_val(my_list):\n",
    "    x = 0\n",
    "    for i in my_list:\n",
    "        x += i\n",
    "    x = x/len(my_list)\n",
    "    x = round(x, 2)\n",
    "    return x\n",
    "\n",
    "#Function calculates the minimum value in a given list\n",
    "def minimum_val(my_list):\n",
    "    x = my_list[0]\n",
    "    for i in my_list:\n",
    "        if i < x:\n",
    "            x = i\n",
    "    return x\n",
    "\n",
    "#maximum value function which will return the maximum value in a given list\n",
    "def maximum_val(my_list):\n",
    "    x = my_list[0]\n",
    "    for i in my_list:\n",
    "        if i > x:\n",
    "            x = i\n",
    "    return x\n",
